// LESSON: Comparator and Ordering - Reference Page 2.
// You will learn: Build comparators for multi-key ordering and null handling.
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;
import java.util.List;
import java.util.TreeSet;

class ComparatorOrderReference {
  public static void main(String[] args) {
    example1SortStrings();
    example2SortPersons();
    example3SortedSet();
  }

  static void example1SortStrings() {
    List<String> names = new ArrayList<>(Arrays.asList("Bo", "Amanda", "Cecilia"));
    names.sort(Comparator.naturalOrder());
    System.out.println(names);
    names.sort(Comparator.reverseOrder());
    System.out.println(names);
  }

  static void example2SortPersons() {
    List<PersonForOrdering> people = new ArrayList<>();
    people.add(new PersonForOrdering("Sara", "Nordin", 19));
    people.add(new PersonForOrdering("Ali", "Nordin", 17));
    people.add(new PersonForOrdering("Maja", "Berg", 20));
    Comparator<PersonForOrdering> byNameAndAge = Comparator.comparing(PersonForOrdering::lastName).thenComparing(PersonForOrdering::firstName).thenComparingInt(PersonForOrdering::age);
    people.sort(byNameAndAge);
    System.out.println(people);
  }

  static void example3SortedSet() {
    Comparator<PersonForOrdering> byFullName = Comparator.comparing(PersonForOrdering::lastName).thenComparing(PersonForOrdering::firstName);
    TreeSet<PersonForOrdering> sortedPeople = new TreeSet<>(byFullName);
    sortedPeople.add(new PersonForOrdering("Eva", "Lund", 18));
    sortedPeople.add(new PersonForOrdering("Adam", "Lund", 18));
    sortedPeople.add(new PersonForOrdering("Eva", "Lund", 22));
    System.out.println(sortedPeople);
  }
}

class PersonForOrdering {
  private final String firstName;
  private final String lastName;
  private final int age;

  PersonForOrdering(String firstName, String lastName, int age) {
    this.firstName = firstName;
    this.lastName = lastName;
    this.age = age;
  }

  String firstName() { return firstName; }
  String lastName() { return lastName; }
  int age() { return age; }
  public String toString() { return firstName + " " + lastName + " (" + age + ")"; }
}
